package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.provider.Settings
import android.widget.Button
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_STRONG
import androidx.biometric.BiometricManager.Authenticators.DEVICE_CREDENTIAL
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo

    private val PREFS_NAME = "MyAppPrefs"
    private val AUTH_STATUS_KEY = "isAuthenticated"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        if (isAuthenticated()) {
            navigateToHomeScreen()
            return
        }

        val loginButton: Button = findViewById(R.id.loginButton)
        loginButton.setOnClickListener {
            // In a real app, this would lead to a username/password login screen
            Toast.makeText(this, "Proceeding to password login...", Toast.LENGTH_SHORT).show()
            // For this example, we'll just consider it authenticated after password login too
            setAuthenticated(true)
            navigateToHomeScreen()
        }

        setupBiometricAuthentication()
        checkBiometricAvailabilityAndPrompt()
    }

    private fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(AUTH_STATUS_KEY, false)
    }

    private fun setAuthenticated(isAuthenticated: Boolean) {
        with(sharedPreferences.edit()) {
            putBoolean(AUTH_STATUS_KEY, isAuthenticated)
            apply()
        }
    }

    private fun navigateToHomeScreen() {
        val intent = Intent(this, HomeScreenActivity::class.java)
        startActivity(intent)
        finish() // Prevent going back to the login screen
    }

    private fun setupBiometricAuthentication() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    Toast.makeText(applicationContext, "Authentication error: $errString", Toast.LENGTH_SHORT).show()
                    // Fallback to password login on error
                    findViewById<Button>(R.id.loginButton).performClick()
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    Toast.makeText(applicationContext, "Authentication succeeded!", Toast.LENGTH_SHORT).show()
                    setAuthenticated(true)
                    navigateToHomeScreen()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    Toast.makeText(applicationContext, "Authentication failed. Try again or use password.", Toast.LENGTH_SHORT).show()
                    // Optionally, you might want to show a button for password login here
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Log in using your fingerprint or face")
            .setNegativeButtonText("Use password") // This makes the fallback explicit
            // For DEVICE_CREDENTIAL, use setAllowedAuthenticators
            .setAllowedAuthenticators(BIOMETRIC_STRONG or DEVICE_CREDENTIAL)
            .build()
    }

    private fun checkBiometricAvailabilityAndPrompt() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(BIOMETRIC_STRONG or DEVICE_CREDENTIAL)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                Toast.makeText(this, "App can authenticate using biometrics.", Toast.LENGTH_SHORT).show()
                biometricPrompt.authenticate(promptInfo)
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                Toast.makeText(this, "No biometric features available on this device.", Toast.LENGTH_LONG).show()
                // Force password login
                findViewById<Button>(R.id.loginButton).performClick()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                Toast.makeText(this, "Biometric features are currently unavailable.", Toast.LENGTH_LONG).show()
                // Force password login
                findViewById<Button>(R.id.loginButton).performClick()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                // Prompts the user to create credentials if they haven't already
                Toast.makeText(this, "No biometrics enrolled. Please enroll biometrics.", Toast.LENGTH_LONG).show()
                val enrollIntent = Intent(Settings.ACTION_BIOMETRIC_ENROLL).apply {
                    putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                        BIOMETRIC_STRONG or DEVICE_CREDENTIAL)
                }
                startActivityForResult(enrollIntent, REQUEST_CODE_BIOMETRIC_ENROLL)
                // Fallback to password login in the meantime
                findViewById<Button>(R.id.loginButton).performClick()
            }
            BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED -> {
                Toast.makeText(this, "Biometric security update required.", Toast.LENGTH_LONG).show()
                findViewById<Button>(R.id.loginButton).performClick()
            }
            BiometricManager.BIOMETRIC_ERROR_UNSUPPORTED -> {
                Toast.makeText(this, "Biometric authentication is unsupported.", Toast.LENGTH_LONG).show()
                findViewById<Button>(R.id.loginButton).performClick()
            }
            BiometricManager.BIOMETRIC_STATUS_UNKNOWN -> {
                Toast.makeText(this, "Unknown biometric status.", Toast.LENGTH_LONG).show()
                findViewById<Button>(R.id.loginButton).performClick()
            }
        }
    }

    companion object {
        const val REQUEST_CODE_BIOMETRIC_ENROLL = 1001
    }
}

